typedef struct DIFFDEVICEATTRIBUTES {   DWORD dwFlags;
DWORD dwFFSamplePeriod;
DWORD dwFFMinTimeResolution;
} DIFFDEVICEATTRIBUTES, *LPDIFFDEVICEATTRIBUTES;
成员 dwFlags
保留供将来使用。 此成员必须设置为零。 dwFFSamplePeriod
指定播放强制命令之间的最短时间（以微秒为单位）。 dwFFMinTimeResolution
指定设备可以解析的最短时间，以微秒为单位。 设备将任意时间值舍入为最接近的受支持增量。 例如，如果 dwFFMinTimeResolution 的值为 1000，则设备将随时舍入到最接
近的毫秒。
typedef struct DIFFOBJECTATTRIBUTES {   DWORD dwFFMaxForce;
DWORD dwFFForceResolution;
} DIFFOBJECTATTRIBUTES, *LPDIFFOBJECTATTRIBUTES;
成员 dwFFMaxForce
指定由与此对象关联的执行器可以创建的最大力的幅度。 力以牛顿表示，并相对于在设备 正常 操作期间手部的位置进行测量。 如果此成员为零，则假定对象不支持力回馈。
dwFFForceResolution
指定与此对象关联的执行器的力分辨率。 返回的值表示力回馈系统可表示的最大力的等
级或细分数，从 0 (无力) 到最大力。

typedef struct DIJOYUSERVALUES {
DWORD            dwSize;   JOYREGUSERVALUES ruv;
WCHAR            wszGlobalDriver[MAX_JOYSTRING];
WCHAR            wszGameportEmulator[MAX_JOYSTRING];} DIJOYUSERVALUES, *LPDIJOYUSERVALUES;
成员 dwSize
指定结构的大小（以字节为单位）。 在使用 结构之前，必须初始化此成员。 ruv
游戏杆用户配置。 除了 mmddk.h 头文件中包含的字段外，以前未使用的
jrvRanges.jpCenter 字段还包含每个轴的用户饱和度级别。 控制面板应用程序根据最终用户在校准或微调期间设置的值设置死区和饱和度值。 死区可以解释为“中心敏感度”，饱和度可以解释为“沿边缘的敏感度”。
wszGlobalDriver[MAX_JOYSTRING] 全局端口驱动程序。
wszGameportEmulator[MAX_JOYSTRING]
未使用。
typedef struct DIOBJECTATTRIBUTES {   DWORD dwFlags;
WORD  wUsagePage;   WORD  wUsage;
} DIOBJECTATTRIBUTES, *LPDIOBJECTATTRIBUTES;
成员 dwFlags
以下标志可能为零、一个或多个： DIDOI_FFACTUATOR
指示对象可以应用强制回馈效果。 DIDOI_FFEFFECTTRIGGER
指示对象可以触发力回馈效果的播放。

HRESULT Unacquire(); 返回值
如果成功，则返回DI_OK;否则，返回 COM 错误代码。
typedef struct joyreghwvalues_tag {   JOYRANGE jrvHardware;
DWORD    dwPOVValues[JOY_POV_NUMDIRS];   DWORD    dwCalFlags;
} JOYREGHWVALUES, *LPJOYREGHWVALUES;
成员 jrvHardware
硬件返回的值。
dwPOVValues[JOY_POV_NUMDIRS] 视点 (POV) 硬件返回的值。 dwCalFlags
已校准的内容。
